// Helper Functions
async function simulateHuman(sock, jid, action = 'composing') {
    await sock.sendPresenceUpdate(action, jid);
    await delay(Math.floor(Math.random() * 2000) + 1000);
    await sock.sendPresenceUpdate('paused', jid);
}

async function getAIResponse(prompt) {
    try {
        const response = await openai.chat.completions.create({
            model: "gpt-3.5-turbo",
            messages: [
                { role: "system", content: "أنت مساعد شرس وذكي جداً لبوت واتساب يسمى [ المُتحكِّم V6 ]. ردودك يجب أن تكون قصيرة، قوية، مفعمة بالإيموجي الشرير، ولا ترحم الأعداء." },
                { role: "user", content: prompt }
            ],
            max_tokens: 150
        });
        return response.choices[0].message.content;
    } catch (e) {
        console.error('AI Error:', e);
        return "💀 النظام مشغول حالياً بسحق أهداف أخرى...";
    }
}

async function startBot() {
    loadDB();
    console.log('💀 جاري تشغيل النسخة الاحترافية V6 [الوضع المتوحش]...');
    
    const { state, saveCreds } = await useMultiFileAuthState(AUTH_DIR);
    const { version } = await fetchLatestBaileysVersion();

    const sock = makeWASocket({
        version,
        auth: state,
        logger: pino({ level: 'silent' }),
        printQRInTerminal: true,
        browser: Browsers.macOS('Desktop'),
        syncFullHistory: false
    });

    sock.ev.on('creds.update', saveCreds);

    sock.ev.on('connection.update', (update) => {
        const { connection, lastDisconnect, qr } = update;
        if (qr) {
            console.clear();
            qrcode.generate(qr, { small: true });
        }
        if (connection === 'close') {
            const shouldReconnect = (lastDisconnect.error instanceof Boom) ? 
                lastDisconnect.error.output.statusCode !== DisconnectReason.loggedOut : true;
            if (shouldReconnect) startBot();
        } else if (connection === 'open') {
            console.log('✅ تم تفعيل [ المُتحكِّم V6 ] - وضع السيطرة المطلقة!');
        }
    });

    sock.ev.on('messages.upsert', async (m) => {
        if (m.type !== 'notify') return;
        const msg = m.messages[0];
        if (!msg.message || msg.key.fromMe) return;

        const jid = msg.key.remoteJid;
        const text = msg.message.conversation || msg.message.extendedTextMessage?.text || '';
        
        // Log message
        db.logs.push({ jid, message: text, timestamp: new Date().toISOString() });
        if (db.logs.length > 1000) db.logs.shift();

        // Get or Create User
        if (!db.users[jid]) {
            db.users[jid] = {
                jid,
                authenticated: 0,
                free_requests: 10,
                is_banned: 0,
                ban_end_time: null,
                join_date: new Date().toISOString(),
                current_action: null // Added to track user\'s current action
            };
        }
        let user = db.users[jid];
        saveDB();

        // Anti-Enemy / Ban Check
        if (user.is_banned) {
            if (user.ban_end_time && Date.now() > user.ban_end_time) {
                user.is_banned = 0;
                user.ban_end_time = null;
                saveDB();
            } else {
                return;
            }
        }

        // Welcome & Auth
        if (!user.authenticated) {
            if (text === PASSWORD) {
                user.authenticated = 1;
                saveDB();
                await simulateHuman(sock, jid);
                await sock.sendMessage(jid, { text: '✅ تم تسجيل الدخول بنجاح أيها الوحش! أرسل "اوامر" لبدء السيطرة 💀🔥' });
            } else {
                const welcomeMsg = `💀 أهلاً بك في جحيم [ المُتحكِّم V6 ] 💀\n\nلقد دخلت منطقة السيطرة. البوت محمي بكلمة سر.\nأرسل كلمة السر للوصول إلى الترسانة! 👺`;
                await sock.sendMessage(jid, { text: welcomeMsg });
            }
            return;
        }

        // Commands
        const cmd = text.toLowerCase();

        if (cmd === 'اوامر') {
            const help = `💀 **قائمة التحكم V6** 💀\n\n` +
                `1. **ذكاء** [نص]: محرك الردود الذكية الشرسة.\n` +
                `2. **قصف**: إرسال هجوم متسلسل من الشتائم المدمرة.\n` +
                `3. **تدمير الاخصام**: ابدأ عملية تدمير الخصم بإرسال الشتائم.\n` + // New command added
                `4. **حالة**: عرض إحصائياتك في النظام.\n` +
                `5. **توقف**: إيقاف الهجوم مؤقتاً.\n\n` +
                `⚠️ **تحذير**: أنت الآن في وضع الوحش.`;
            await sock.sendMessage(jid, { text: help });
        } 
        else if (cmd.startsWith('ذكاء ')) {
            const prompt = text.slice(5);
            await simulateHuman(sock, jid);
            const response = await getAIResponse(prompt);
            await sock.sendMessage(jid, { text: response });
        }
        else if (cmd === 'قصف') {
            // Sequential Beast Attack
            for (let i = 0; i < 5; i++) {
                const insult = insults[Math.floor(Math.random() * insults.length)];
                await simulateHuman(sock, jid);
                await sock.sendMessage(jid, { text: insult });
                await delay(1000); // 1 second delay
            }
        }
        else if (cmd === 'تدمير الاخصام') { // New command handler
            user.current_action = 'waiting_for_victim_number';
            saveDB();
            await simulateHuman(sock, jid);
            await sock.sendMessage(jid, { text: 'أعطني رقم الضحية (مثال: 201234567890) 😈' });
        }
        else if (user.current_action === 'waiting_for_victim_number') {
            const victimNumber = text.replace(/[^0-9]/g, ''); // Clean input to get only digits
            if (victimNumber) {
                const victimJid = victimNumber + '@s.whatsapp.net';
                await simulateHuman(sock, jid);
                await sock.sendMessage(jid, { text: `بدء عملية تدمير الخصم ${victimNumber}... 💥` });
                for (let i = 0; i < insults.length; i++) { // Send all insults from the array
                    const insult = insults[i];
                    await simulateHuman(sock, victimJid);
                    await sock.sendMessage(victimJid, { text: insult });
                    await delay(500); // Small delay between insults
                }
                await simulateHuman(sock, jid);
                await sock.sendMessage(jid, { text: `✅ تم تدمير الخصم ${victimNumber} بنجاح! 😈` });
            } else {
                await simulateHuman(sock, jid);
                await sock.sendMessage(jid, { text: 'رقم الضحية غير صالح. يرجى إدخال رقم صحيح. 💀' });
            }
            user.current_action = null; // Reset action
            saveDB();
        }
        else if (cmd === 'حالة') {
            const stats = `📊 **حالتك أيها القائد**:\n` +
                `• المعرف: ${jid}\n` +
                `• تاريخ الانضمام: ${new Date(user.join_date).toLocaleDateString()}\n` +
                `• الطلبات المجانية: ${user.free_requests}`;
            await sock.sendMessage(jid, { text: stats });
        }
    });
}

startBot().catch(console.error);
